5	/**
6	 * Handler for the `trackgentic blockages add <blockedId> --by <blockerId...>` command.
7	 */
8	export async function blockagesAddAction(
9	  blockedId: string,
10	  options: { by: string[] },
11	): Promise<void> {
12	  try {
13	    const tracker = new Tracker();
14	    const blockerIds = typeof options.by === "string" ? [options.by] : options.by;
15	    const result = await tracker.blockagesAdd(blockedId, { blockerIds });
16	    if (result instanceof TrackgenticError) {
17	      writeStderr({ result: result.result, message: result.message });
18	      process.exit(result.exitCode);
19	    }
20	    writeStdout(result);
21	    process.exit(0);
22	  } catch (err) {
23	    if (err instanceof TrackgenticError) {
24	      writeStderr({ result: err.result, message: err.message });
25	      process.exit(err.exitCode);
26	    }
27	    writeStderr({ result: "INTERNAL_ERROR", message: (err as Error).message });
28	    process.exit(1);
29	  }
30	}
