1	import { join } from "node:path";
2	import type { BlockageEntry, DependenciesFile, IssueId } from "../types";
3	import { atomicWriteJSON, readJSON } from "./file-io";
4	
5	const DEPS_FILE = "dependencies.json";
6	
7	/**
8	 * Read dependencies.json from the tracker directory.
9	 */
10	export async function readDependencies(trackerDir: string): Promise<DependenciesFile> {
11	  return readJSON<DependenciesFile>(join(trackerDir, DEPS_FILE));
12	}
13	
14	/**
15	 * Write dependencies.json atomically.
16	 */
17	export async function writeDependencies(
18	  trackerDir: string,
19	  deps: DependenciesFile,
20	): Promise<void> {
21	  await atomicWriteJSON(join(trackerDir, DEPS_FILE), deps);
22	}
