936	  /**
937	   * Add blockage dependencies to an issue.
938	   * Batch atomic: if any blocker would create a cycle, the entire batch is rejected.
939	   */
940	  async blockagesAdd(blockedId: IssueId, params: BlockagesAddParams): Promise<BlockagesAddResult> {
941	    const trackerDir = resolveTrackerDir(this.cwd);
942	    if (!trackerDir) {
943	      throw new TrackgenticError(
944	        ErrorCodes.NOT_INITIALIZED.result,
945	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
946	        ErrorCodes.NOT_INITIALIZED.exitCode,
947	      );
948	    }
949	
950	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
951	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
952	    const authResult = resolveAuthor({ config, users, requiresWrite: true });
953	    if (authResult instanceof TrackgenticError) return authResult;
954	    const author = params.author ?? authResult.author;
955	
956	    const index = await readIndex(trackerDir);
957	
958	    // Validate blockedId exists
959	    if (!findEntry(index, blockedId)) {
960	      throw new TrackgenticError(
961	        ErrorCodes.NOT_FOUND.result,
962	        `Issue ${blockedId} not found in index.`,
963	        ErrorCodes.NOT_FOUND.exitCode,
964	      );
965	    }
966	
967	    // Validate all blockerIds exist
968	    for (const blockerId of params.blockerIds) {
969	      if (!findEntry(index, blockerId)) {
970	        throw new TrackgenticError(
971	          ErrorCodes.NOT_FOUND.result,
972	          `Issue ${blockerId} not found in index.`,
973	          ErrorCodes.NOT_FOUND.exitCode,
974	        );
975	      }
976	    }
977	
978	    const deps = await readDependencies(trackerDir);
979	
980	    // Projected state: deep clone and validate cycle for each blocker
981	    let projected = {
982	      blockedBy: { ...deps.blockedBy },
983	      blocks: { ...deps.blocks },
984	    };
985	
986	    for (const blockerId of params.blockerIds) {
987	      projected = addBlockage(projected, blockedId, blockerId);
988	      if (detectCycle(projected, blockedId, blockerId)) {
989	        throw new TrackgenticError(
990	          ErrorCodes.BLOCKAGE_CYCLE.result,
991	          `Blockage would create a cycle: ${blockedId} → ... → ${blockerId}`,
992	          ErrorCodes.BLOCKAGE_CYCLE.exitCode,
993	        );
994	      }
