997	    // All passed — write projected state
998	    await writeDependencies(trackerDir, projected);
999	
1000	    // Append events to blockedId's issue file
1001	    const blockedEntry = findEntry(index, blockedId)!;
1002	    const issueFilePath = join(trackerDir, blockedEntry.path);
1003	
1004	    for (const blockerId of params.blockerIds) {
